#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 用户与行为证据
  9.2 问题空间归位
  9.3 惯例与心智模型匹配
  9.4 工具与保真度选型
  9.5 系统与一致性归属
  9.6 可访问性与伦理风险
  9.7 时效与衰减核验

背后的心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 
  • 先解决对的问题（问题空间 vs 方案空间）: 先确保在解决**对的问题**，再把问题解好——发散-收敛的双钻节奏，问题空间没收敛就别进方案空间，更别进像素。 (figures: Cagan / Torres / Brown)

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "用户与行为证据"
  "问题空间归位"
  "惯例与心智模型匹配"
  "工具与保真度选型"
  "系统与一致性归属"
  "可访问性与伦理风险"
  "时效与衰减核验"
)
declare -a DIM_QUESTIONS=(
  "目标用户是谁、有没有可观察的真实行为数据/可用性测试证据，而非口头偏好或自己的假设。"
  "当前在双钻的哪一格（Discover/Define/Develop/Deliver）、是否过早进入方案/像素、这是不是个值得做的真问题（JTBD）。"
  "相关平台/竞品的既有模式与用户已有心智模型，本方案是遵循还是打破、打破是否划算。"
  "当前阶段该用什么保真度与什么工具，AI 生成是否适用、是否会被锁定/过时。"
  "这个一致性/合规需求该在页面层还是设计系统 token/组件层解决、是否已有真值源。"
  "方案是否满足 WCAG/EAA 基准、是否含 dark pattern 或操纵性设计、合规与伦理风险。"
  "涉及的工具/AI 能力/法规是否处于高 decay 区、结论的\"保鲜期\"多长、是否需 self-verify。"
)
declare -a DIM_SOURCES=(
  "现有可用性测试记录、Dovetail 研究库、Clarity/Hotjar 行为录屏、Amplitude 漏斗；缺则规划一次折扣测试或访谈。"
  "产品 brief、机会树/discovery 记录、有没有 outcome 而非 output 的目标定义。"
  "平台 HIG/Material 规范、竞品同类流程、NN/g 相关模式文章。"
  "Track 02 工具决策树、Figma/Penpot/Maze 等能力边界、新兴 AI 工具的 Decay 状态。"
  "设计系统文档（zeroheight/Storybook）、token 定义、组件库治理状态。"
  "WCAG 2.2 / EN 301 549 清单、对比度/键盘检查、deceptive.design 模式库、DSA/FTC 监管口径。"
  "Track 02 新兴层 Decay 标注、Config/NN/g 最新文章、法规生效时间线。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "1–2 句\"行为证据显示 X / 当前无证据，需补 Y 验证\"。"
  "1–2 句\"当前处于 X 阶段，问题已/未收敛，建议先做 Z\"。"
  "1–2 句\"遵循惯例 X / 破例需满足 Y 才划算\"。"
  "1–2 句\"用 X 工具 + Y 保真度，理由 Z\"。"
  "1–2 句\"做进系统层 X / 暂在页面层但登记设计债\"。"
  "1–2 句\"a11y 达标/缺口 X；无/有 dark pattern 风险 Y\"。"
  "1–2 句\"该结论 Decay risk = X，建议 Y 月内复核 / 立即 self-verify Z\"。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
